import React from 'react';
import logo from './icaro.gif';
import './App.css';

class App extends React.Component {
  constructor(props) {
    super();
    this.state = {
      countM: 0,
      countS: 10,
      style: 500
    }
  }

  startClick = () => {
    this.getTime();
    const run = this.runningBike();
    this.myInterval = setInterval(() => {
      if (this.state.countM === 0 && this.state.countS === 0) {
        this.setState({
          countS: 0,
          countM: 0
        });
        alert('Acabou a pausa');
        this.resetClick();
        return;
      }
      if (this.state.countS === 0) {
        this.setState((prevState, _props) => ({
          countS: 60,
          countM: prevState.countM - 1
        }))
      };
      this.setState((prevState, _props) => ({
        countS: prevState.countS - 1,
        style: prevState.style - run
      }))
    }, 1000);
  }

  resetClick = () => {
    clearInterval(this.myInterval);
  }

  getTime = () => {
    this.setState({
      countM: this.minuteInput.value,
      countS: this.secondInput.value
    })
    if (this.minuteInput.value === '') {
      this.setState({
        countM: 0,
      })
    }
    if (this.secondInput.value === '') {
      this.setState({
        countS: 0,
      })
    }
  }

  runningBike = () => {
    const seconds1 = this.minuteInput.value === '' ? 0 : (this.minuteInput.value * 60);
    const seconds2 = this.secondInput.value === '' ? 0 : this.minuteInput.value;
    return Math.round((500 / (seconds1 + seconds2)), -1);
  }

  render() {
    return (
      <div className="App">
        <header className="App-header">
          <div className="bike">
            <img src={logo} className="icaro" style={{ right: `${this.state.style}px` }} />
          </div>
          <p>
            Stopwatch
          </p>
          <section className="stopwatch">
            <span>{(this.state.countM >= 10) ? this.state.countM : "0" + this.state.countM}</span>&nbsp;:&nbsp;
            <span>{(this.state.countS >= 10) ? this.state.countS : "0" + this.state.countS}</span>
          </section>
          <section>
            <label>
              Minutos:
                <input type="number" min="0" max="59" ref={(input) => this.minuteInput = input}></input>
            </label>
            <label>
              Segundos:
                <input type="number" min="0" max="59" ref={(input) => this.secondInput = input}></input>
            </label>
            <button onClick={this.startClick}>Iniciar</button>
            <button onClick={this.resetClick}>Parar</button>
          </section>
        </header>
      </div>
    );
  }

}

export default App;
